def main():
    import sys
    S = sys.stdin.readline().strip()
    count = {}
    for char in S:
        count[char] = count.get(char, 0) + 1
    # Find the character that appears only once
    unique_char = next(char for char, freq in count.items() if freq == 1)
    # Find the index of the unique character
    for i, char in enumerate(S):
        if char == unique_char:
            print(i + 1)
            break

if __name__ == "__main__":
    main()
